# Test power operator (**)
# Integer power
a: int = 2
b: int = 3
result1: int = a ** b
print("2 ** 3 =", result1)

# Larger powers
c: int = 5
d: int = 4
result2: int = c ** d
print("5 ** 4 =", result2)

# Power of zero
e: int = 10
f: int = 0
result3: int = e ** f
print("10 ** 0 =", result3)

# Power of one
g: int = 7
h: int = 1
result4: int = g ** h
print("7 ** 1 =", result4)

# Float power
x: float = 2.0
y: float = 3.0
result5: float = x ** y
print("2.0 ** 3.0 =", result5)
